@namespace Lumeo
@implements IAsyncDisposable
@inject ComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div id="@_elementId" class="@CssClass" role="toolbar" aria-label="@EffectiveAriaLabel" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Maximum scale factor applied to the item closest to the cursor (e.g. 1.8 = 80% bigger).</summary>
    [Parameter] public double MaxScale { get; set; } = 1.8;
    /// <summary>Radius (px) around each item within which neighbors start scaling.</summary>
    [Parameter] public int MagnifyRadius { get; set; } = 100;
    /// <summary>Accessible label for the dock toolbar container. Defaults to "Application Dock".</summary>
    [Parameter] public string? AriaLabel { get; set; }
    private string EffectiveAriaLabel => AriaLabel ?? L["Dock.ApplicationDock"];
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _elementId = $"lumeo-dock-{Guid.NewGuid():N}";
    private bool _registered;
    private double _lastMaxScale;
    private int _lastRadius;

    private string CssClass => string.Join(" ", new[] { "lumeo-dock", Class }.Where(s => !string.IsNullOrWhiteSpace(s)));

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && !_registered)
        {
            _registered = true;
            _lastMaxScale = MaxScale;
            _lastRadius = MagnifyRadius;
            try
            {
                await Interop.MotionDock(_elementId, new
                {
                    maxScale = MaxScale,
                    magnifyRadius = MagnifyRadius
                });
            }
            catch (JSDisconnectedException) { }
        }
        else if (_registered && (MaxScale != _lastMaxScale || MagnifyRadius != _lastRadius))
        {
            // MaxScale / MagnifyRadius changed at runtime. The JS dock() captures
            // these into a closure at registration time, so they must be re-pushed.
            // Dispose first: dock() always adds a fresh listener set and overwrites
            // its disconnect handle, so a naive re-invoke would leak the previous
            // listeners — disposeDock removes the old set before we rebind.
            _lastMaxScale = MaxScale;
            _lastRadius = MagnifyRadius;
            try
            {
                await Interop.MotionDisposeDock(_elementId);
                await Interop.MotionDock(_elementId, new
                {
                    maxScale = MaxScale,
                    magnifyRadius = MagnifyRadius
                });
            }
            catch (JSDisconnectedException) { }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (!_registered) return;
        try { await Interop.MotionDisposeDock(_elementId); }
        catch (JSDisconnectedException) { }
    }
}
